class ChessGameImpl extends RustOpaque implements ChessGame {
  // Not to be used by end users
  ChessGameImpl.frbInternalDcoDecode(List<dynamic> wire)
    : super.frbInternalDcoDecode(wire, _kStaticData);

  // Not to be used by end users
  ChessGameImpl.frbInternalSseDecode(BigInt ptr, int externalSizeOnNative)
    : super.frbInternalSseDecode(ptr, externalSizeOnNative, _kStaticData);

  static final _kStaticData = RustArcStaticData(
    rustArcIncrementStrongCount:
        RustLib.instance.api.rust_arc_increment_strong_count_ChessGame,
    rustArcDecrementStrongCount:
        RustLib.instance.api.rust_arc_decrement_strong_count_ChessGame,
    rustArcDecrementStrongCountPtr:
        RustLib.instance.api.rust_arc_decrement_strong_count_ChessGamePtr,
  );

  /// Cheap clock-only snapshot (no board build).
  ClockSnapshot clockSnapshot() =>
      RustLib.instance.api.crateApiGameChessGameClockSnapshot(that: this);

  /// Crazyhouse: legal squares to drop the reserve piece `piece` (0=Pawn ..
  /// 4=Queen) onto.
  Uint32List dropTargets({required int piece}) => RustLib.instance.api
      .crateApiGameChessGameDropTargets(that: this, piece: piece);

  /// Bughouse: receive a piece passed from the partner's board into `color`'s
  /// reserve. Refreshes status (a fed piece can create a drop-mate escape).
  void giveToHand({required PieceColor color, required PieceKind piece}) =>
      RustLib.instance.api.crateApiGameChessGameGiveToHand(
        that: this,
        color: color,
        piece: piece,
      );

  /// Position-hash history (for the AI's repetition avoidance).
  Uint64List hashHistory() =>
      RustLib.instance.api.crateApiGameChessGameHashHistory(that: this);

  /// Bughouse: the piece the last applied move made available to pass to the
  /// partner (already demoted to a pawn if it was a promoted piece).
  PieceKind? lastPassableCapture() =>
      RustLib.instance.api.crateApiGameChessGameLastPassableCapture(that: this);

  /// Destination squares of every legal move starting from `from` (for hints).
  Uint32List legalTargets({required int from}) => RustLib.instance.api
      .crateApiGameChessGameLegalTargets(that: this, from: from);

  /// The moves played so far in UCI form (for saving a game).
  List<String> moveHistoryUci() =>
      RustLib.instance.api.crateApiGameChessGameMoveHistoryUci(that: this);

  /// Try to play from→to (with optional promotion piece).
  MoveOutcome play({
    required int from,
    required int to,
    PieceKind? promotion,
  }) => RustLib.instance.api.crateApiGameChessGamePlay(
    that: this,
    from: from,
    to: to,
    promotion: promotion,
  );

  /// Crazyhouse: drop reserve `piece` (0=Pawn .. 4=Queen) onto square `to`.
  MoveOutcome playDrop({required int piece, required int to}) => RustLib
      .instance
      .api
      .crateApiGameChessGamePlayDrop(that: this, piece: piece, to: to);

  /// Apply a move given in UCI/coordinate form (e.g. `e2e4`, `e7e8q`), used
  /// to apply the AI's chosen move. Returns false if illegal/over.
  bool playUci({required String uci}) =>
      RustLib.instance.api.crateApiGameChessGamePlayUci(that: this, uci: uci);

  /// Geometric destination squares for the piece on `from`, ignoring whose
  /// turn it is (for premove candidate highlighting). Approximate: validity is
  /// re-checked when the premove is actually executed.
  Uint32List premoveTargets({required int from}) => RustLib.instance.api
      .crateApiGameChessGamePremoveTargets(that: this, from: from);

  /// Premove targets for `from` AFTER the queued premoves are applied as raw
  /// relocations (flattened from,to pairs: [f0,t0,f1,t1,…]). Lets a premove
  /// *chain* target the board the earlier premoves would produce. Each
