  }) => RustLib.instance.api.crateApiGameChessGameSetClockMs(
    that: this,
    whiteMs: whiteMs,
    blackMs: blackMs,
  );

  /// Advance the running side's clock by `elapsed_ms`. Latches a timeout when
  /// the side to move flags.
  void tick({required int elapsedMs}) => RustLib.instance.api
      .crateApiGameChessGameTick(that: this, elapsedMs: elapsedMs);

